def _normalize(section):
    return str(section).lower().replace("-", "_").replace(" ", "_")


def _crpc_doc(section, title, domain, focus, consequence, related, case_law, procedure):
    return {
        "id": f"crpc_{_normalize(section)}",
        "title": f"CrPC Section {section} - {title}",
        "section": f"Section {section}",
        "domain": domain,
        "content": f"""Section {section} of the Code of Criminal Procedure, 1973 deals with {title.lower()}. {focus} The provision works as part of a larger procedural chain linking police powers, magistrate supervision, fair-trial guarantees, bail, remand, evidence handling, and appellate review. Because criminal procedure controls how the State may investigate, arrest, charge, try, and punish, even a seemingly technical requirement under the CrPC can have direct constitutional significance under Articles 20, 21, and 22.

Legal consequence or practical effect: {consequence} Related provisions and procedural companions include {related}. In litigation, judges usually ask whether the statutory step was mandatory or directory, whether prejudice has been caused, and whether the accused, victim, complainant, or investigating agency can rely on the defect or compliance to seek a remedy. This makes careful procedural sequencing essential in criminal practice.

Important interpretive points and case law: {case_law} Practically speaking, {procedure}. Advocates therefore treat Section {section} not as an isolated clause but as part of the architecture of due process, efficient investigation, and judicial control over coercive State power.""",
    }


CRPC_CORPUS = [
    _crpc_doc(section='2', title='Definitions', domain='Criminal', focus='Section 2 supplies many foundational definitions used throughout criminal procedure, including complaint, inquiry, investigation, cognizable and non-cognizable offence, bailable and non-bailable offence, and officer in charge of a police station. While the FIR itself is dealt with in Section 154, the definitional scheme under Section 2 helps determine whether police may investigate without prior magistrate permission.', consequence='The section is not penal; its importance lies in classification. Whether an offence is cognizable or non-cognizable directly affects arrest power, investigation, and the route to court.', related='Sections 154 to 157 CrPC, special statute schedules, arrest and bail provisions, and the First Schedule classification tables', case_law='Courts repeatedly stress that procedural labels matter because an erroneous classification can taint arrest, investigation, and cognizance. The First Schedule and the special law creating the offence are often read together.', procedure='lawyers first identify the exact offence section, then use Section 2 concepts and the First Schedule to determine whether FIR, NCR, arrest, warrant, or magistrate permission is required'),
    _crpc_doc(section='41', title='Arrest Without Warrant', domain='Criminal', focus='Section 41 authorises police arrest without warrant in specified cognizable cases, but the power is not unbounded. The amended provision requires officers to justify arrest through necessity factors such as preventing further offence, proper investigation, preventing evidence tampering, or ensuring presence in court.', consequence='Non-compliance can make arrest illegal, support bail, trigger departmental action, and even compensation in appropriate constitutional proceedings.', related='Sections 41A, 46, 49, 50, 57, 60A CrPC and Articles 21 and 22 of the Constitution', case_law='Arnesh Kumar v State of Bihar is the leading authority requiring police to avoid automatic arrest, especially in offences punishable up to seven years, and requiring magistrates to examine the arrest checklist.', procedure='officers are expected to record reasons for arrest or for not arresting, consider notice of appearance under Section 41A, and produce the arrested person promptly before the magistrate'),
    _crpc_doc(section='46', title='How Arrest is Made', domain='Criminal', focus='Section 46 sets out the manner of making an arrest: actual touching or confinement of the body, or submission to custody. It also regulates use of force and states that a woman shall not ordinarily be arrested after sunset except in exceptional circumstances with prior permission.', consequence='The provision limits coercive force and helps courts test whether a claimed arrest was lawful, excessive, or merely a formal detention dressed up after the event.', related='Sections 41, 49, 50, 51, 53, 57 CrPC, D.K. Basu guidelines, and constitutional safeguards against arbitrary detention', case_law='Courts insist that arrest is a serious invasion of liberty and therefore method, timing, identification of officers, and documentation all matter when legality is challenged.', procedure='practically, arrest memos, time of arrest, witness attestation, notice to relative, and safe handling of the detainee are central compliance points'),
    _crpc_doc(section='49', title='No Unnecessary Restraint', domain='Criminal', focus='Section 49 states that the arrested person shall not be subjected to more restraint than is necessary to prevent escape. It embodies the proportionality principle in custodial handling.', consequence='There is no separate punishment clause inside the section, but violation can invite constitutional remedies, departmental action, exclusionary criticism at trial, and scrutiny for custodial violence or degrading treatment.', related='Article 21, D.K. Basu, prison manuals, handcuffing jurisprudence, and police conduct regulations', case_law='Sunil Batra and later custodial rights cases stress dignity and restraint in treatment of persons in custody. Handcuffing requires justification and cannot be routine.', procedure='courts look at medical reports, CCTV, photographs, arrest memos, and the reasons recorded by police if excessive force or restraints were used'),
    _crpc_doc(section='50', title='Grounds of Arrest to be Informed and Right to Bail', domain='Criminal', focus='Section 50 requires that every arrested person be informed of full particulars of the offence or other grounds of arrest. In bailable offences, the person must also be informed of the right to be released on bail.', consequence='Failure to communicate grounds can invalidate detention, strengthen habeas corpus or bail arguments, and amount to breach of Article 22(1).', related='Article 22, Sections 41B, 41D, 56, 57, 436, 437 CrPC', case_law='The Supreme Court repeatedly treats communication of grounds as a substantive safeguard, not a technical formality, because a person cannot seek legal assistance or bail without knowing the accusation.', procedure='police should state the offence, show or read the arrest memo, note the time, and communicate the right to arrange surety where the offence is bailable'),
    _crpc_doc(section='57', title='Person Arrested Not to be Detained More Than Twenty-Four Hours', domain='Criminal', focus='Section 57 embodies the classic 24-hour rule. A person arrested without warrant cannot be detained by police for more than twenty-four hours, excluding travel time to the magistrate, unless special remand is obtained under Section 167.', consequence='Continued detention beyond this limit is illegal and exposes the State to release orders, compensation claims, and adverse judicial findings.', related='Article 22(2), Sections 56, 57, 167 CrPC, habeas corpus jurisdiction, and custodial rights case law', case_law='D.K. Basu and a long line of liberty cases treat the 24-hour rule as one of the minimum constitutional guarantees against police excess.', procedure='the investigating officer must either release the person, produce the person before the magistrate, or seek remand before the 24-hour period expires'),
    _crpc_doc(section='60A', title='Arrests to be Made Strictly According to the Code', domain='Criminal', focus='Section 60A was inserted to make explicit that arrest shall be made strictly in accordance with the CrPC. It is a reinforcing provision aimed at curbing informal, extra-legal, or convenience-based custody practices.', consequence='The section is not separately punitive, but it sharpens judicial review of arrest legality and supports bail or compensation arguments when officers bypass statutory safeguards.', related='Sections 41, 41A, 46, 49, 50, 57 CrPC and Articles 21 and 22', case_law='Post-Arnesh Kumar jurisprudence uses Section 60A to emphasise that arrest is not a routine step in every cognizable case.', procedure='lawyers test every arrest against the code: power, necessity, memo, information to relatives, production before magistrate, and compliance with notice provisions'),
    _crpc_doc(section='125', title='Maintenance of Wives, Children and Parents', domain='Family', focus='Section 125 creates a swift, secular maintenance remedy for wives, children, and parents who are unable to maintain themselves and are neglected by a person with sufficient means. Though placed in the CrPC, it is social justice legislation rather than punitive criminal law.', consequence='The principal consequence is a maintenance order enforceable by the magistrate. Non-payment can lead to recovery mechanisms and imprisonment for breach of the order, but the object is support, not punishment.', related='Family law maintenance statutes, Shah Bano, Danial Latifi, domestic violence monetary relief, and evidence of income, neglect, and inability to maintain', case_law='Shah Bano made clear that the remedy applies irrespective of religion. Courts also assess earning capacity, standard of living, and whether the claimant is living separately for sufficient reason.', procedure='the applicant files before the magistrate, proves relationship, neglect, and need, and the respondent contests means, liability, and quantum'),
    _crpc_doc(section='144', title='Power to Issue Order in Urgent Cases of Nuisance or Apprehended Danger', domain='Criminal', focus='Section 144 empowers an Executive Magistrate to issue immediate orders in urgent situations involving nuisance, danger, obstruction, riot, or disturbance of public tranquillity. It is preventive and temporary, not a substitute for ordinary law-making.', consequence='Breach of a valid order can trigger prosecution under Section 188 IPC. At the same time, overbroad or repetitive use may be quashed for violating constitutional freedoms.', related='Public order law, Sections 129 to 132 CrPC, Article 19, and judicial review of prohibitory orders', case_law='In Anuradha Bhasin, the Supreme Court held that Section 144 cannot be used as a tool for suppressing legitimate opinion and must satisfy necessity and proportionality.', procedure='magistrates must record material facts, specify the danger, tailor the order to the situation, and ensure the order is open to challenge and periodic review'),
    _crpc_doc(section='154', title='Information in Cognizable Cases (FIR)', domain='Criminal', focus='Section 154 governs registration of the First Information Report in cognizable offences. Oral information must be reduced to writing, read over to the informant, signed by the informant, and entered in the prescribed book.', consequence='Failure to register a cognizable complaint can invite supervisory directions, disciplinary action, or recourse to magistrate and constitutional remedies. The FIR sets the criminal law in motion but is not substantive evidence of truth.', related='Sections 155 to 157 CrPC, Lalita Kumari guidelines, zero FIR practice, and police station jurisdiction rules', case_law='Lalita Kumari v Government of Uttar Pradesh held that registration is mandatory where information discloses a cognizable offence, though a brief preliminary inquiry may be permissible in limited categories.', procedure='the informant should insist on a copy of the FIR, preserve complaint details, and escalate to superior police officers or the magistrate if registration is refused'),
    _crpc_doc(section='155', title='Information as to Non-Cognizable Cases', domain='Criminal', focus="Section 155 deals with non-cognizable offences, where police record the substance in a station diary and ordinarily refer the informant to the magistrate. Investigation cannot proceed without the magistrate's order unless a cognizable offence is also disclosed.", consequence='The section limits police initiative in minor matters and prevents informal conversion of non-cognizable complaints into full investigations without judicial control.', related='Sections 2, 154, 155, 156 CrPC, station diary practice, and combined cognizable/non-cognizable case handling', case_law='Courts examine whether police wrongly bypassed the magistrate or whether the facts actually disclosed a cognizable offence despite the initial label.', procedure='the complainant may approach the magistrate for appropriate orders if police treat the matter as non-cognizable or decline effective action'),
    _crpc_doc(section='156', title="Police Officer's Power to Investigate Cognizable Case", domain='Criminal', focus="Section 156 authorises police investigation into cognizable offences without a magistrate's order and permits magistrates under Section 156(3) to direct registration and investigation. It is a key gateway provision in pre-trial criminal process.", consequence='Orders under Section 156(3) can revive a refused complaint and require formal investigation, but the magistrate must apply mind and avoid mechanical directions.', related='Sections 154, 156, 157, 190, 200 CrPC, affidavit requirements in private complaints, and supervisory jurisdiction', case_law='Priyanka Srivastava required applications under Section 156(3) to be supported by affidavit to deter abuse and false invocation.', procedure='litigants first approach police, then superior officers, and if necessary seek a speaking order from the magistrate directing registration or investigation'),
    _crpc_doc(section='157', title='Procedure for Investigation', domain='Criminal', focus='Section 157 requires the officer in charge to send a report to the magistrate and proceed to the spot to investigate when there is reason to suspect commission of a cognizable offence. It structures the early stage of investigation.', consequence='The section is not penal, but delay or unexplained deviation may undermine the prosecution case, especially in grave offences where promptness matters.', related='FIR, site inspection, inquest, seizure, witness examination, and final report under Section 173', case_law='Courts consider prompt dispatch of the special report and early investigative steps as indicators of genuineness, though every delay is not fatal if explained.', procedure='police normally visit the scene, secure evidence, examine witnesses, make seizures, and keep the magistrate informed through required reports'),
    _crpc_doc(section='161', title='Examination of Witnesses by Police', domain='Criminal', focus='Section 161 empowers police to orally examine persons acquainted with the facts and circumstances of the case during investigation. Their answers are reduced into statements for investigative use.', consequence='Such statements are not substantive evidence at trial, but they are crucial for contradiction, corroborative investigation, and assessing whether the prosecution version has materially changed.', related='Sections 161 and 162 CrPC, hostile witness law, evidentiary contradictions, and rights against self-incrimination for accused persons', case_law='Courts caution against over-reliance on police statements because they are not made on oath and are susceptible to omission disputes. Contradictions must be properly proved.', procedure='investigators record statements promptly, identify omissions or improvements, and later confront witnesses in cross-examination through the investigating officer'),
    _crpc_doc(section='162', title='Statements to Police Not to be Signed; Limited Use at Trial', domain='Criminal', focus='Section 162 restricts the evidentiary use of statements made to police during investigation. They are not signed and cannot be used as substantive evidence except for contradiction in the manner allowed by the Evidence Act.', consequence='This rule prevents police-generated narratives from replacing courtroom testimony on oath. Improper reliance can vitiate findings.', related='Section 161 CrPC, Section 145 Evidence Act, confessions, omissions, and prior inconsistent statements', case_law='Courts draw a strict line between substantive testimony in court and prior police statements. Only duly proved contradictions count.', procedure='trial lawyers carefully mark contradictions, confront the witness, and prove the relevant portion through the investigating officer'),
    _crpc_doc(section='163', title='No Inducement, Threat or Promise by Police', domain='Criminal', focus='Section 163 prohibits investigating officers from offering inducement, threat, or promise to obtain statements. It is a fairness safeguard that complements the law on confessions and custodial protection.', consequence='Statements extracted through coercion are vulnerable to exclusion, judicial distrust, and collateral allegations of custodial misconduct.', related='Sections 24 to 27 Evidence Act, Section 164 CrPC confessions, Articles 20(3) and 21, and custodial rights jurisprudence', case_law='Courts are deeply suspicious of statements appearing to be the product of pressure, especially in custody or prolonged interrogation settings.', procedure='where coercion is alleged, courts look to timing, medical condition, access to lawyer or family, independent production before magistrate, and consistency with later retractions'),
    _crpc_doc(section='164', title='Recording of Confessions and Statements by Magistrate', domain='Criminal', focus='Section 164 allows a magistrate to record confessions and certain statements, especially in serious cases. The magistrate must ensure voluntariness and give the accused time for reflection before recording a confession.', consequence='A properly recorded confession can be powerful evidence; an improperly recorded one may be excluded or treated as unreliable. Statements of victims or key witnesses under this section also carry practical importance.', related='Evidence Act rules on confessions, Section 163 CrPC, sexual offence investigations, and retraction jurisprudence', case_law="Courts insist on strict compliance with warning, voluntariness, and certification requirements. For victims' statements, promptness and procedural fairness improve evidentiary value.", procedure='the magistrate isolates the person from police influence, explains consequences, records voluntariness, and preserves the statement in the prescribed form'),
    _crpc_doc(section='167', title='Procedure When Investigation Cannot Be Completed in Twenty-Four Hours (Remand)', domain='Criminal', focus='Section 167 governs remand when investigation cannot be completed within twenty-four hours. It authorises magistrates to permit police or judicial custody for limited periods and sets outer limits for default bail when charge-sheet is delayed.', consequence='The consequence is central to liberty: illegal remand can invalidate detention, while failure to file the final report in time may trigger indefeasible default bail under the statutory period applicable to the offence.', related='Sections 57, 167, 173, 436A CrPC, default bail jurisprudence, and special statutes modifying remand periods', case_law='Courts strictly police remand reasons, production requirements, and the right to default bail once the statutory period expires and the accused applies before filing of the charge-sheet.', procedure='magistrates review the case diary, grounds for custody, progress of investigation, and whether police custody is genuinely needed or judicial custody is sufficient'),
    _crpc_doc(section='173', title='Report of Police Officer on Completion of Investigation (Charge-Sheet)', domain='Criminal', focus='Section 173 requires police to forward the final report after completing investigation. The report may be a charge-sheet, closure report, or other final form depending on the evidence collected.', consequence='Filing of the report triggers the cognizance stage, supply of papers, and commencement of pre-trial court scrutiny. Defects in investigation do not always nullify proceedings, but missing essentials can affect discharge or trial.', related='Sections 157, 167, 173, 190, 207, 209 CrPC and further investigation principles', case_law='Courts permit further investigation in appropriate cases and distinguish it from impermissible reinvestigation. The content of the report must fairly present the material collected.', procedure="the report usually encloses witness lists, seizure memos, expert opinions, injury reports, and the investigating officer's conclusion on whether sufficient evidence exists"),
    _crpc_doc(section='190', title='Cognizance of Offences by Magistrates', domain='Criminal', focus='Section 190 empowers magistrates to take cognizance on receiving a complaint, a police report, or information from any person other than a police officer, or upon their own knowledge. Cognizance marks application of judicial mind to proceed according to law.', consequence='The provision determines the gateway to judicial proceedings. A flawed cognizance order may be challenged, but detailed evaluation of evidence is not required at this stage.', related='Sections 156(3), 190, 200, 202, 204 CrPC and revisional or inherent jurisdiction', case_law='Courts emphasise that cognizance is of the offence, not the offender, and that the magistrate need only see whether a prima facie basis exists to proceed under the chosen route.', procedure='the magistrate examines the source material, chooses the procedural track, and may postpone process for inquiry or issue summons or warrant if the threshold is met'),
    _crpc_doc(section='197', title='Sanction for Prosecution of Judges and Public Servants', domain='Criminal', focus='Section 197 protects certain public servants from prosecution for acts done while acting or purporting to act in the discharge of official duty unless prior sanction is obtained. The protection is functional, not personal.', consequence='Without valid sanction, the court may be barred from taking cognizance. At the same time, the shield does not extend to acts wholly unrelated to official duty or committed for private motives.', related='Public servant corruption cases, official duty tests, CrPC cognizance, and special sanction provisions under other statutes', case_law='The Supreme Court has repeatedly held that there must be a reasonable nexus between the act complained of and official duty; mere status as a public servant is insufficient.', procedure='courts examine the complaint, the nature of office, and the connection between the act and official duty before deciding whether sanction is mandatory'),
    _crpc_doc(section='200', title='Examination of Complainant', domain='Criminal', focus='Section 200 applies to private complaints. The magistrate examines the complainant and witnesses on oath before deciding whether there is sufficient ground to proceed, subject to statutory exceptions.', consequence='This stage filters frivolous complaints and creates an early sworn record. Failure to follow the mandatory procedure may affect the validity of subsequent process.', related='Sections 190, 200, 202, 203, 204 CrPC and complaint-case procedure', case_law='Courts require a real application of mind and not a mechanical recital. The magistrate must understand the accusation and the supporting material before issuing process.', procedure='complainants should present concise facts, supporting documents, and available witnesses; the magistrate may later order inquiry or issue summons if a prima facie case appears'),
    _crpc_doc(section='204', title='Issue of Process', domain='Criminal', focus='Section 204 empowers the magistrate to issue summons or warrant if there is sufficient ground for proceeding in a complaint or police-report case. It is the transition point from preliminary scrutiny to formal accused-facing process.', consequence='Improper issuance of process can be challenged in revision or quashing. Yet the threshold is only prima facie satisfaction, not proof beyond reasonable doubt.', related='Sections 200, 202, 204 CrPC, summons and warrant procedure, and inherent powers of the High Court', case_law='Higher courts have warned against routine issue of process without analysing whether the essential ingredients of the alleged offence are disclosed.', procedure='the court chooses the correct mode of process, ensures jurisdiction, and records sufficient reasons to show application of mind'),
    _crpc_doc(section='209', title='Commitment of Case to Court of Session', domain='Criminal', focus='Section 209 requires the magistrate to commit the case to the Court of Session when the offence is triable exclusively by that court. The magistrate does not conduct a full trial or weigh evidence at this stage.', consequence='Commitment transfers the matter into the Sessions framework for consideration of charge, discharge, and trial. Delay or omission can affect case flow but usually not the ultimate merits.', related='Sections 207, 208, 209, 227, 228 CrPC and the schedule of offences triable by Court of Session', case_law="The magistrate's role is largely ministerial once the case is shown to be sessions-triable and the necessary papers are supplied.", procedure='the case records, statements, and documents are transmitted to the Sessions Court after compliance with supply requirements'),
    _crpc_doc(section='227', title='Discharge by Court of Session', domain='Criminal', focus='Section 227 allows the Sessions Court to discharge the accused if, upon consideration of the record and hearing the parties, there is not sufficient ground for proceeding. It protects against unnecessary trial where the material is plainly inadequate.', consequence='Discharge ends the prosecution at the threshold in the Sessions Court unless reversed. It differs from acquittal because evidence is not yet recorded in a full trial.', related='Sections 227 and 228 CrPC, framing of charge, revisional remedies, and prima facie case doctrine', case_law='At this stage the court does not conduct a mini-trial, but it may sift the material to see whether grave suspicion exists. Suspicion alone without material is not enough.', procedure='defence counsel attacks missing ingredients, unreliable recovery, legal bars, and inherent improbabilities; the prosecution argues that trial evidence is needed'),
    _crpc_doc(section='228', title='Framing of Charge', domain='Criminal', focus='Section 228 provides that if the Sessions Judge finds ground for presuming that the accused has committed an offence triable by the court, a charge shall be framed. The charge crystallises the accusation for trial.', consequence='The section determines the exact offence that the accused must meet at trial. Misframing may later require alteration, but early precision affects evidence strategy and plea decisions.', related='Sections 227, 228, 216 CrPC and the law governing contents of charge', case_law='The test is not proof but grave suspicion founded on material. Courts avoid detailed weighing of defence explanations unless they completely destroy the prosecution version.', procedure='the judge identifies the precise penal sections, reads and explains the charge to the accused, and records the plea'),
    _crpc_doc(section='229', title='Conviction on Plea of Guilty', domain='Criminal', focus='Section 229 allows the Sessions Judge to convict the accused on a plea of guilty if the judge, in discretion, accepts the plea. The court must ensure that the plea is voluntary, informed, and unambiguous.', consequence='A valid guilty plea can lead directly to conviction and sentencing, but the court may still insist on evidence in serious matters where caution is warranted.', related='Charge framing, sentencing, legal representation, and appellate issues concerning voluntariness of plea', case_law='Courts proceed carefully, especially in grave offences, to avoid convicting on an unclear or uninformed plea.', procedure="the judge records the plea in the accused's own understanding, confirms voluntariness, and then either convicts or directs regular trial"),
    _crpc_doc(section='232', title='Acquittal', domain='Criminal', focus='Section 232 requires the Sessions Judge to acquit the accused if, after taking the prosecution evidence and hearing the prosecution and defence, there is no evidence that the accused committed the offence. It is a stage-specific safeguard against unnecessary defence evidence.', consequence='If the prosecution completely fails to establish a case requiring answer, the accused need not be called upon to enter defence. This preserves the burden of proof.', related='Sessions trial structure, Section 313 examination, defence evidence, and final judgment provisions', case_law='The provision reflects the settled principle that an accused cannot be compelled to answer a vacuum. Courts assess whether there is any legally admissible evidence connecting the accused.', procedure='defence counsel seeks acquittal by highlighting total absence of proof on essential ingredients before the case is pushed further'),
    _crpc_doc(section='235', title='Judgment of Acquittal or Conviction', domain='Criminal', focus='Section 235 governs the final judgment in a Sessions trial and, upon conviction, requires the court to hear the accused on sentence. It separates adjudication of guilt from sentencing in serious cases.', consequence='The provision ensures reasoned judgment and an individualized sentencing hearing, which is especially important in offences carrying severe punishment.', related='Sentencing jurisprudence, victim impact, compensation, probation in suitable cases, and appellate review', case_law='The Supreme Court has repeatedly stressed meaningful hearing on sentence, consideration of mitigating and aggravating factors, and reasoned findings on both conviction and punishment.', procedure='after deciding guilt, the court hears submissions on age, antecedents, role, possibility of reform, victim harm, and statutory minimum or maximum punishment'),
    _crpc_doc(section='265A-265L', title='Plea Bargaining', domain='Criminal', focus='Sections 265A to 265L introduce plea bargaining in specified cases, excluding serious offences, offences affecting socio-economic conditions as notified, and offences against women or children in many contexts. The mechanism seeks speedy, consensual disposal with judicial supervision.', consequence='The result may be a mutually satisfactory disposition, reduced sentence, compensation, and closure without full trial. However, voluntariness is essential and the process cannot be used where the statute excludes it.', related='Application procedure, mutually satisfactory disposition, victim compensation, sentencing relief, and finality provisions within Chapter XXI-A CrPC', case_law='Indian plea bargaining is narrower than some foreign models because the judge actively verifies voluntariness and legality, and the process is not available for every offence.', procedure='the accused files an application, the court conducts in camera verification, notices stakeholders, facilitates settlement on compensation or disposition, and then passes a final order if the bargain is lawful'),
    _crpc_doc(section='302', title='Permission to Conduct Prosecution', domain='Criminal', focus='Section 302 allows a magistrate to permit a private person to conduct the prosecution, subject to conditions and without displacing overall control of the court. It is distinct from the Sessions trial prosecutor framework.', consequence='The section gives victims or interested complainants a limited route to participate more actively when justified, though fairness to the accused and orderly trial remain paramount.', related='Assistant public prosecutors, complainant participation, victim rights, and court control over criminal proceedings', case_law="Courts balance the complainant's interest against the need for impartial conduct of prosecution and avoidance of vindictive or disorderly trial management.", procedure='an applicant must show sufficient reason for permission, and the magistrate may regulate the extent of participation'),
    _crpc_doc(section='309', title='Power to Postpone or Adjourn Proceedings', domain='Criminal', focus='Section 309 empowers criminal courts to postpone or adjourn proceedings for reasons recorded, but it also embodies the duty to proceed expeditiously. In witness-in-court stages, day-to-day trial is emphasised to avoid delay and witness fatigue.', consequence='Repeated unnecessary adjournments can prejudice both sides, dilute evidence, and violate the right to speedy trial. Courts may impose costs or refuse casual requests.', related='Speedy trial jurisprudence, witness management, Section 317 CrPC, and case-flow discipline', case_law='The Supreme Court frequently criticises routine adjournment culture and stresses that serious trials should continue with discipline once evidence begins.', procedure='judges record reasons, balance fairness with expedition, and consider whether illness, absent documents, settlement talks, or other grounds truly justify postponement'),
    _crpc_doc(section='313', title='Power to Examine the Accused', domain='Criminal', focus='Section 313 allows the court to put incriminating circumstances appearing in evidence to the accused and obtain an explanation. It is a crucial fairness device because no adverse circumstance should be used without confronting the accused.', consequence="Omission to put material circumstances can weaken the prosecution's reliance on them, though not every defect automatically vitiates the trial unless prejudice is shown.", related='Burden of proof, right to silence, defence explanation, and appellate scrutiny of prejudice', case_law='Courts treat Section 313 as substantive, not ornamental. A meaningful examination helps the court assess denials, explanations, alibi, and admissions.', procedure="questions should be simple and specific, covering all incriminating material; the accused's answers are not given on oath but can be considered alongside the evidence"),
    _crpc_doc(section='317', title='Provision for Inquiries and Trial Being Held in Absence of Accused in Certain Cases', domain='Criminal', focus="Section 317 allows the court, for reasons recorded, to dispense with personal attendance of the accused or proceed in the accused's absence in suitable situations when presence is not necessary in the interests of justice.", consequence='The provision offers flexibility but cannot be used to deny a fair chance to participate in the case. It is commonly applied in summons cases, represented accused situations, or limited hearings.', related="Sections 205, 273, 317 CrPC and the accused's right to be present at material stages", case_law='Courts weigh inconvenience, nature of evidence, representation by counsel, and whether prejudice would be caused by dispensing with attendance.', procedure='the accused applies through counsel or the court acts suo motu, records reasons, and imposes conditions where necessary'),
    _crpc_doc(section='320', title='Compounding of Offences', domain='Criminal', focus='Section 320 lists compoundable offences and specifies whether permission of the court is required. Compounding reflects the policy that some disputes can be lawfully settled by the victim and accused without full prosecution.', consequence='A valid compounding results in acquittal of the accused for that offence. Non-compoundable offences generally cannot be settled through this section, though High Courts may quash some disputes under Section 482 in exceptional circumstances.', related='Tables of compoundable offences, victim consent, Section 482 CrPC, and settlement jurisprudence', case_law='Gian Singh and later decisions distinguish statutory compounding from quashing in the interest of justice, especially in private or matrimonial disputes.', procedure='the parties file compromise terms, the court verifies voluntariness and statutory permissibility, and then records compounding or declines it'),
    _crpc_doc(section='321', title='Withdrawal from Prosecution', domain='Criminal', focus='Section 321 permits the Public Prosecutor, with consent of the court, to withdraw from prosecution before judgment. The power is not political whim; it must be exercised in good faith and in the interest of justice.', consequence='If permitted, the accused is discharged or acquitted depending on the stage. Abuse of the provision can be judicially checked.', related='Role of Public Prosecutor, court supervision, public interest, and separation between executive suggestion and prosecutorial discretion', case_law='Courts insist that the prosecutor must independently apply mind and the judge must evaluate whether withdrawal serves justice rather than shield influential persons.', procedure='a formal application is moved, reasons are examined, and the court decides whether to grant consent'),
    _crpc_doc(section='327', title='Court to be Open', domain='Criminal', focus='Section 327 states the general rule that criminal courts are open to the public, reinforcing transparency and public confidence. It also creates important exceptions for in camera proceedings in sexual offence matters.', consequence='The section is not punitive, but violation of privacy-sensitive exceptions can seriously prejudice victims and may attract contempt or statutory consequences under other laws.', related='Open justice doctrine, sexual offence confidentiality, media reporting limits, and witness protection concerns', case_law='Courts balance transparency with dignity and privacy, especially in rape and child sexual offence trials where public exclusion may be mandatory or strongly justified.', procedure='trial courts ordinarily remain open, but they may direct in camera proceedings and restrict publication where law so requires'),
    _crpc_doc(section='340', title='Procedure in Cases Regarding Offences Affecting Administration of Justice', domain='Criminal', focus='Section 340 provides the procedure for courts to make a complaint regarding offences such as perjury, fabrication of evidence, and false declarations affecting administration of justice. It is meant to prevent casual perjury prosecutions while preserving judicial authority.', consequence='The court must consider whether it is expedient in the interests of justice to prosecute. Not every false statement warrants action; materiality and deliberate intention matter.', related='Sections 191 to 200 and 211 IPC, Section 195 CrPC bars, and evidence concerning intentional falsity', case_law='The Supreme Court has held that expediency in the interests of justice is the controlling test; courts should not launch prosecution for every inconsistency or mistake.', procedure='the court may conduct a preliminary inquiry, record reasons, and file a written complaint before the competent magistrate'),
    _crpc_doc(section='360', title='Order to Release on Probation of Good Conduct or After Admonition', domain='Criminal', focus='Section 360 allows release of certain offenders on probation of good conduct or after admonition instead of sentencing them to imprisonment, subject to age, nature of offence, antecedents, and other circumstances.', consequence='The section reflects reformative sentencing. It may spare a first-time or less serious offender from incarceration while still keeping the finding of guilt on record.', related='Probation of Offenders Act, sentencing policy, rehabilitation, and victim-impact considerations', case_law='Where the Probation of Offenders Act applies, it usually prevails. Courts nevertheless discuss Section 360 when considering alternatives to imprisonment for suitable offenders.', procedure='the court considers age, antecedents, gravity, social background, and prospects of reform before releasing the offender on conditions'),
    _crpc_doc(section='374', title='Appeals from Conviction', domain='Criminal', focus='Section 374 identifies who may appeal from conviction and to which appellate forum. It is a major safeguard because trial findings on guilt and sentence are subject to re-examination in law and on evidence.', consequence='An appeal may result in acquittal, retrial, conviction for a lesser offence, reduction or enhancement of sentence subject to law, or affirmation of the judgment.', related='Suspension of sentence, appellate procedure, bail during appeal, and standards of review', case_law="Appellate courts reappreciate evidence, especially in serious cases, and ensure that the trial court's reasoning meets legal standards of proof and fairness.", procedure='the convicted person files appeal within limitation, seeks records, and often applies for suspension of sentence pending hearing'),
    _crpc_doc(section='397', title='Calling for Records to Exercise Revisional Powers', domain='Criminal', focus='Section 397 gives Sessions Courts and High Courts revisional power to call for and examine records to satisfy themselves about legality, propriety, and regularity of proceedings or orders. Revision is narrower than appeal.', consequence='The revisional court may correct jurisdictional, legal, or procedural errors, but it ordinarily does not substitute itself as a full fact-finding court in every case.', related='Sections 397 to 401 CrPC, interlocutory order bar, and inherent jurisdiction under Section 482', case_law='A recurring issue is whether the challenged order is interlocutory. Courts prevent revision from becoming a disguised appeal against every interim order.', procedure='the applicant identifies patent illegality, jurisdictional error, or miscarriage of justice rather than seeking wholesale re-trial of facts'),
    _crpc_doc(section='401', title="High Court's Powers of Revision", domain='Criminal', focus="Section 401 sets out the High Court's revisional powers, enabling it to exercise most appellate powers in appropriate revision cases, subject to statutory limits and fairness to the accused and other parties.", consequence='The High Court can correct grave errors, but it cannot convert acquittal to conviction in revision without following strict limits. Revision remains discretionary and supervisory.', related='Sections 397 and 401 CrPC, Section 482 inherent power, and appellate alternatives', case_law='High Courts use revision to cure manifest illegality, miscarriage of justice, or jurisdictional defect while respecting the limited nature of the remedy.', procedure='practitioners must show why revision is maintainable, why no adequate alternate remedy exists, and how the impugned order causes serious injustice'),
    _crpc_doc(section='437', title='Bail in Non-Bailable Offences', domain='Criminal', focus='Section 437 governs grant of bail by magistrates in non-bailable offences. It balances liberty with public safety, severity of accusation, likelihood of tampering, and antecedents, while creating restrictions for offences punishable with death or life imprisonment.', consequence='The section determines whether the accused remains in custody pending trial, subject to conditions such as attendance, non-tampering, and travel restrictions.', related='Sections 436, 437, 438, 439 CrPC, parity, antecedents, victim concerns, and constitutional bail jurisprudence', case_law='Courts weigh gravity, prima facie case, possibility of absconding, repeat offending, and needs of investigation. Bail is the rule but not mechanically so in grave offences.', procedure='the defence highlights weak evidence, cooperation, roots in society, and delay; the prosecution emphasises seriousness, recovery needs, and intimidation risks'),
    _crpc_doc(section='438', title='Anticipatory Bail', domain='Criminal', focus='Section 438 allows the High Court or Court of Session to grant anticipatory bail to a person apprehending arrest. It is a pre-arrest liberty mechanism designed to prevent abuse of arrest power.', consequence='If granted, the applicant obtains protection from immediate custody subject to conditions such as joining investigation, non-tampering, and availability for interrogation.', related='Sections 41, 41A, 438, 439 CrPC, Arnesh Kumar, and guidelines on balancing liberty with investigation', case_law='Gurbaksh Singh Sibbia is the foundational judgment holding that anticipatory bail is an important facet of personal liberty and should not be cut down by inflexible formulas.', procedure='the applicant shows a real apprehension of arrest, background of dispute, willingness to cooperate, and absence of custodial interrogation necessity'),
    _crpc_doc(section='439', title='Special Powers of High Court or Court of Session Regarding Bail', domain='Criminal', focus='Section 439 confers broader bail powers on the High Court and Court of Session, including in serious offences and the power to impose or modify conditions. These courts also entertain cancellation applications.', consequence='The section can secure release where magistrate powers are constrained, especially in grave offences or after rejection below. It also supports cancellation when liberty is misused.', related='Sections 437, 438, 439 CrPC, cancellation of bail, supervening circumstances, and parity arguments', case_law='Higher courts assess seriousness, evidence, custody period, trial delay, and constitutional liberty. Bail once granted is not cancelled lightly unless misuse or new circumstances are shown.', procedure='petitions under Section 439 often rely on charge-sheet filing, long incarceration, parity, weak motive, and settled roots; cancellation applications rely on witness tampering or violation of conditions'),
    _crpc_doc(section='440', title='Amount of Bond and Reduction', domain='Criminal', focus='Section 440 requires that the amount of bond and bail bond shall not be excessive. It recognises that liberty cannot be made illusory by unaffordable financial conditions.', consequence="Courts may reduce excessive bond amounts and tailor conditions to the accused's circumstances so that release is real rather than merely theoretical.", related='Bail jurisprudence, surety practice, personal bonds, undertrial rights, and constitutional equality principles', case_law='The Supreme Court has repeatedly noted that poor persons cannot be denied liberty because they cannot furnish unrealistic sureties or cash conditions.', procedure='accused persons may seek modification of bond terms by showing financial incapacity, stable address, and low flight risk'),
    _crpc_doc(section='468', title='Bar to Taking Cognizance After Lapse of Limitation', domain='Criminal', focus='Section 468 bars cognizance of certain offences after expiry of limitation periods linked to the maximum punishment. It aims to discourage stale minor prosecutions while preserving court power to condone delay in suitable cases under Section 473.', consequence='If applicable and not properly condoned, the bar prevents the magistrate from validly taking cognizance. It often arises in complaint cases and regulatory prosecutions.', related='Sections 468 to 473 CrPC, continuing offence doctrine, and calculation of limitation', case_law='Courts examine the date of offence, date of knowledge where relevant, continuing wrong arguments, and whether sufficient cause exists to extend limitation.', procedure='the accused raises limitation early; the complainant or prosecution may seek condonation with reasons for delay'),
    _crpc_doc(section='482', title='Inherent Powers of High Court', domain='Criminal', focus='Section 482 preserves the inherent powers of the High Court to make orders necessary to give effect to the code, prevent abuse of process, or secure the ends of justice. It is extraordinary and not a substitute for routine appeal or revision.', consequence='The High Court may quash FIRs, complaints, charge-sheets, or proceedings in suitable cases, stay abuse, or pass ancillary directions where ordinary procedure is insufficient.', related='Quashing jurisprudence, settlement cases, lack of ingredients, jurisdictional defects, Sections 397 and 401 CrPC, and Article 226', case_law='Bhajan Lal remains the classic framework for quashing, especially where allegations are absurd, barred by law, or fail to disclose any offence even if taken at face value.', procedure='petitions typically annex the FIR or complaint, undisputed documents, and legal grounds showing that continuation of proceedings would be oppressive or futile'),
]
